const d = $input.item.json.Felder || $input.item.json;
const systemPrompt = `Du bist der Social-Media-Texter der Physiotherapiepraxis Physio Fuchs.
Du schreibst Instagram-Captions auf Deutsch fuer eine moderne, empathische Physiotherapiepraxis.
TONALITAET:
- Warm, professionell, motivierend - nie arrogant oder klinisch
- Duzen der Community ist erwuenscht
- Emojis: maximal 3-5 pro Caption, nur unterstuetzend
- Keine Clickbait-Formulierungen
- Keine medizinischen Versprechen (kein 'heilt', 'kuriert')
- Erlaubt: 'kann helfen', 'unterstuetzt', 'lindert haeufig'
CAPTION-AUFBAU:
1. Hook (erste Zeile, max. 12 Woerter) - stopp-wuerdig, direkte Ansprache
2. Hauptinhalt (3-5 Saetze) - Mehrwert, Tipps oder konkreter Einblick
3. Handlungsaufruf (1 Satz) - Termin buchen, Kommentieren oder Beitrag speichern
WICHTIG: Keine Hashtags in der Caption selbst.
AUSGABE: Nur reines JSON ohne Markdown-Backticks oder erklaerenden Text davor/danach.
Exaktes Format:
{"variante_1":{"caption":"...","hook_preview":"...(erste 15 Zeichen)","ton":"informativ"},"variante_2":{"caption":"...","hook_preview":"...","ton":"persoenlich"},"variante_3":{"caption":"...","hook_preview":"...","ton":"motivierend"},"hashtag_set_1":["#tag1","#tag2"],"hashtag_set_2":["#tag1","#tag2"]}`;

const thema   = d.Field_1 || 'Physiotherapie';
const postTyp = d.Field_2 || 'Tipp';
const brief   = d.Field_3 || '';
const hashtag = d.Field_7 || '';
const monat   = new Date().getMonth();
const jahreszeit = monat <= 1 || monat === 11 ? 'Winter' : monat <= 4 ? 'Frühling' : monat <= 7 ? 'Sommer' : 'Herbst';

const userMessage = `BRIEF VON JUDITH:\nThema: ${thema}\nPost-Typ: ${postTyp}\nAnweisung: ${brief}\nKONTEXT: Jahreszeit: ${jahreszeit}\nHASHTAG-POOL: #physiofuchs #physiotherapie #physio #gesundheit ${hashtag}\nErstelle alle 3 Varianten. Nur reines JSON.`;

return {
  json: {
    model: 'claude-sonnet-4-6',
    max_tokens: 2048,
    system: systemPrompt,
    messages: [{ role: 'user', content: userMessage }]
  }
};

const response = $input.item.json;
if (!response.content || !response.content[0]) throw new Error('Keine Antwort von Claude');
const rawText = response.content[0].text;
let parsed;
try { parsed = JSON.parse(rawText.replace(/```json\n?/gi,'').replace(/```\n?/g,'').trim()); }
catch(e) {
  const match = rawText.match(/\{[\s\S]*\}/);
  if (match) { try { parsed = JSON.parse(match[0]); } catch(e2) { throw new Error('Kein valides JSON'); } }
  else throw new Error('Kein JSON gefunden');
}
const i = response.usage?.input_tokens || 0;
const o = response.usage?.output_tokens || 0;
return { json: {
  v1_caption: parsed.variante_1?.caption || '', v1_hook: parsed.variante_1?.hook_preview || '', v1_ton: parsed.variante_1?.ton || 'informativ',
  v2_caption: parsed.variante_2?.caption || '', v2_hook: parsed.variante_2?.hook_preview || '', v2_ton: parsed.variante_2?.ton || 'persoenlich',
  v3_caption: parsed.variante_3?.caption || '', v3_hook: parsed.variante_3?.hook_preview || '', v3_ton: parsed.variante_3?.ton || 'motivierend',
  hashtags_set_1:   Array.isArray(parsed.hashtag_set_1) ? parsed.hashtag_set_1.join(' ') : '',
  hashtags_set_2:   Array.isArray(parsed.hashtag_set_2) ? parsed.hashtag_set_2.join(' ') : '',
  hashtags_array_1: parsed.hashtag_set_1 || [],
  input_tokens: i, output_tokens: o,
  cost_eur: Math.round((i*0.000003+o*0.000015)*100)/100,
  generated_at: new Date().toISOString(),
  model: 'claude-sonnet-4-20250514'
}};

const json = $input.item.json;
const f = json.Felder || json.fields || {};

// Item-ID sauber: parseInt + trim gegen Leerzeichen in URL
const rawId = json.AUSWEIS || json.id || json.ID || 0;
const itemId = parseInt(String(rawId).trim(), 10);

// Datum formatieren: "11052026" → "11.05.2026"
const rawDatum = String(f.Field_4 || f.field_4 || '');
const digits = rawDatum.replace(/\D/g,'');
const datumFormatiert = digits.length >= 8
  ? digits.substring(0,2)+'.'+digits.substring(2,4)+'.'+digits.substring(4,8)
  : rawDatum || '(kein Datum)';

return { json: { ...json,
  sharepoint_item_id: itemId,
  thema:   f.Field_1 || f.field_1 || f.Title || '(kein Thema)',
  datum:   datumFormatiert,
  uhrzeit: f.Field_5 || f.field_5 || '(keine Uhrzeit)',
}};

