const json = $input.item.json;
const antwortRaw = String(json.Daten?.text || json.data?.text || json.data || json.response || json.text || '').trim();
const match = antwortRaw.match(/[123]/);
if (!match) throw new Error(`Ungültige Antwort: "${antwortRaw}". Bitte 1, 2 oder 3.`);
const wahl = parseInt(match[0]);
const prev = $('Felder aufbereiten').item.json;
const v = {
  1:{caption:prev.v1_caption, ton:prev.v1_ton, hook:prev.v1_hook},
  2:{caption:prev.v2_caption, ton:prev.v2_ton, hook:prev.v2_hook},
  3:{caption:prev.v3_caption, ton:prev.v3_ton, hook:prev.v3_hook}
};
const g = v[wahl];
return { json: { ...prev,
  gewaehlte_variante: wahl,
  final_caption:      g.caption,
  final_ton:          g.ton,
  final_hook:         g.hook,
  final_hashtags:     prev.hashtags_set_1,
  final_post:         g.caption + '\n\n' + prev.hashtags_set_1,
  freigabe_zeitpunkt: new Date().toISOString(),
}};
